('business:1-5-stakeholders-in-business:match:0174d301', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stakeholder”?", "options": ["A stakeholder who is part of the business itself — specifically the owners and employees who work within it.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community.", "An owner of shares in a limited company who receives dividends as a return on their investment.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities."]}'::jsonb, '{"answer": 3, "explain": "“Stakeholder” means: An individual or group of people who have an interest in a business and are affected by, or can affect, its activities."}'::jsonb),
('business:1-5-stakeholders-in-business:match:6c78580d', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Internal stakeholder”?", "options": ["A stakeholder who is part of the business itself — specifically the owners and employees who work within it.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community.", "An owner of shares in a limited company who receives dividends as a return on their investment.", "A share of the company''s profits paid out to shareholders as a reward for investing their money in the business."]}'::jsonb, '{"answer": 0, "explain": "“Internal stakeholder” means: A stakeholder who is part of the business itself — specifically the owners and employees who work within it."}'::jsonb),
('business:1-5-stakeholders-in-business:match:41929c46', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “External stakeholder”?", "options": ["An owner of shares in a limited company who receives dividends as a return on their investment.", "A share of the company''s profits paid out to shareholders as a reward for investing their money in the business.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages."]}'::jsonb, '{"answer": 2, "explain": "“External stakeholder” means: A stakeholder who exists outside the business, including customers, suppliers, the government and the local community."}'::jsonb),
('business:1-5-stakeholders-in-business:match:19b54bfd', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Shareholder”?", "options": ["A share of the company''s profits paid out to shareholders as a reward for investing their money in the business.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages.", "An owner of shares in a limited company who receives dividends as a return on their investment.", "When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions."]}'::jsonb, '{"answer": 2, "explain": "“Shareholder” means: An owner of shares in a limited company who receives dividends as a return on their investment."}'::jsonb),
('business:1-5-stakeholders-in-business:match:470825ed', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dividend”?", "options": ["A share of the company''s profits paid out to shareholders as a reward for investing their money in the business.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages.", "When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions.", "When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing."]}'::jsonb, '{"answer": 0, "explain": "“Dividend” means: A share of the company''s profits paid out to shareholders as a reward for investing their money in the business."}'::jsonb),
('business:1-5-stakeholders-in-business:match:7b5b797e', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Conflicting objectives”?", "options": ["When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions.", "When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing.", "A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages."]}'::jsonb, '{"answer": 3, "explain": "“Conflicting objectives” means: When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages."}'::jsonb),
('business:1-5-stakeholders-in-business:match:8ae084a8', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Strike”?", "options": ["When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing.", "A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions."]}'::jsonb, '{"answer": 3, "explain": "“Strike” means: When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions."}'::jsonb),
('business:1-5-stakeholders-in-business:match:7f77af26', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer boycott”?", "options": ["A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing."]}'::jsonb, '{"answer": 3, "explain": "“Customer boycott” means: When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing."}'::jsonb),
('business:1-5-stakeholders-in-business:match:6a216a89', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Corporation tax”?", "options": ["A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions."]}'::jsonb, '{"answer": 2, "explain": "“Corporation tax” means: A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners."}'::jsonb),
('business:1-5-stakeholders-in-business:match:ebc56eff', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National Living Wage”?", "options": ["A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities."]}'::jsonb, '{"answer": 0, "explain": "“National Living Wage” means: A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs."}'::jsonb),
('business:1-5-stakeholders-in-business:match:f7b2b18d', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Grant”?", "options": ["The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities.", "A stakeholder who is part of the business itself — specifically the owners and employees who work within it."]}'::jsonb, '{"answer": 1, "explain": "“Grant” means: Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves."}'::jsonb),
('business:1-5-stakeholders-in-business:match:a31d5321', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stakeholder influence”?", "options": ["The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities.", "A stakeholder who is part of the business itself — specifically the owners and employees who work within it.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community."]}'::jsonb, '{"answer": 0, "explain": "“Stakeholder influence” means: The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions."}'::jsonb),
('business:1-6-business-growth:exam:135ec4d1', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Two vets agree to combine their practices and operate as one business. This is an example of a:", "options": ["Diversification", "Horizontal takeover", "Merger", "Vertical takeover"], "hint": "Did the two businesses agree, or did one buy the other? Also consider whether they are in the same or different industries.", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Merger [1 mark]</h5><p><strong>Why C is correct:</strong> Both practices mutually agreed to combine — this is the definition of a merger. It is not a takeover because neither business bought control of the other.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Diversification:</strong> Both are in the same industry (veterinary), not unrelated industries.</li><li><strong>B — Horizontal takeover:</strong> Although horizontal (same industry), the businesses agreed to combine — making it a merger, not a takeover. A takeover requires one buying control of the other.</li><li><strong>D — Vertical takeover:</strong> The businesses are at the same stage of the same industry, not at different stages of a supply chain.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:6335da63', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Eve is a restaurant owner. She has successfully used social media to attract a lot of new customers to eat in her restaurant. This is an example of:", "options": ["Diversification", "Invention", "Organic growth", "Skimming"], "hint": "Has Eve merged with or bought another business? Or has she grown her customer base from within using her own marketing?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Organic growth [1 mark]</h5><p><strong>Why C is correct:</strong> Eve has grown her business internally by improving marketing (social media). Gaining new customers through marketing is organic growth — no external business was involved.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Diversification:</strong> Involves merging with/taking over a business in an unrelated industry. Eve has not joined with any other business.</li><li><strong>B — Invention:</strong> Creating a brand new product or service. Eve has not invented anything — she is just marketing her existing restaurant.</li><li><strong>D — Skimming:</strong> A pricing strategy where a high initial price is charged for a new product. Eve is using a marketing strategy, not a pricing strategy.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:5effbbc0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A manufacturer of jam buys a fruit farm. This is an example of:", "options": ["A business partnership", "A vertical takeover", "Diversification", "Flexible working"], "hint": "The fruit farm supplies the raw materials (fruit) to the jam maker. Is the jam maker moving backward or forward in the supply chain?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — A vertical takeover [1 mark]</h5><p><strong>Why B is correct:</strong> The jam manufacturer is buying its supplier (the fruit farm), moving backwards up the supply chain. Since one business is buying the other (not a mutual agreement), it is a takeover. Backward vertical + takeover = vertical takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — A business partnership:</strong> A partnership is a type of business ownership structure, not a form of external growth.</li><li><strong>C — Diversification:</strong> Diversification means buying a business in a completely unrelated industry. A fruit farm directly supplies the jam maker — they are connected, so this is vertical not diversification.</li><li><strong>D — Flexible working:</strong> Flexible working is an HR concept about working patterns. Entirely unrelated to business growth.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:30212ada', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q7", "question": "A business has gained more customers by improving the way it markets its products. Which one of the following statements must be true for this business?", "options": ["The business has developed a new product", "The business has grown organically", "The business has increased its market share", "The business has made a profit"], "hint": "Focus on the word ''must''. Only one of these is definitely true in ALL cases when a business gains customers through better marketing.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — The business has grown organically [1 mark]</h5><p><strong>Why B is correct:</strong> Gaining customers through improved marketing is internal to the business — this is organic growth by definition. This MUST be true because the business has grown from within, without any external acquisition.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Developed a new product:</strong> Not necessarily — better marketing could be for existing products. No new product was needed.</li><li><strong>C — Increased its market share:</strong> Not necessarily. If the total market grew faster than the business, its market share could actually have fallen even though it gained more customers.</li><li><strong>D — Made a profit:</strong> Not necessarily — the business may have high costs elsewhere and still operate at a loss despite gaining more customers.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:c2e1bff3', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q9", "question": "A well-known restaurant chain buys another well-known restaurant chain. What is this an example of?", "options": ["A horizontal takeover", "A vertical merger", "Diversification", "Innovation"], "hint": "Both businesses are restaurant chains. One is BUYING the other. Are they at the same or different stages of production?", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — A horizontal takeover [1 mark]</h5><p><strong>Why A is correct:</strong> Both businesses are restaurant chains — same industry, same stage of production = horizontal. One is buying the other (not mutual agreement) = takeover. Horizontal + takeover = horizontal takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — A vertical merger:</strong> Vertical means different stages of the supply chain (e.g., restaurant buying a food supplier). Both are restaurants = same stage = horizontal. Also ''buys'' = takeover, not a mutual merger.</li><li><strong>C — Diversification:</strong> Diversification means entering an unrelated industry. Both are in the restaurant industry.</li><li><strong>D — Innovation:</strong> Innovation = developing new products or processes. Buying another business is not innovation.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:9ef077fc', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Apple MCQ", "question": "Which of the following statements describes a takeover?", "options": ["Orange and T-Mobile joined together to become EE", "Disney the film-maker bought the cartoon animation company Pixar", "Honda Motor Company builds a factory to manufacture gear boxes for its cars", "Netflix increases its share of the market"], "caseStudy": "Apple was started in 1976 and is now the largest company in the world. It began by making and selling desktop computers and its first order was for 50 computers sold at $666 each, bringing in revenue of $33,300. In 2016, its revenue had grown to $49.6bn — a huge increase, even allowing for price rises since 1976. During its history, Apple has taken over only a very small number of other businesses. Apple has researched and developed a range of successful products, including laptop computers such as the MacBook Pro, mobile phones (iPhone), tablet computers (iPad) and services such as Apple Pay. Apple has run some very effective marketing campaigns. It often introduces new products around September and advertises them heavily in the lead-up to Christmas. Its advertising is very innovative, using catchy music, a confident narrator and minimalistic backgrounds in order to focus attention on its products.", "hint": "A takeover is when one business PURCHASES control of another. Look for a scenario where money was paid to acquire another company.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Disney bought Pixar [1 mark]</h5><p><strong>Why B is correct:</strong> Disney acquired (purchased) Pixar — one business buying a controlling interest in another is a takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Orange and T-Mobile:</strong> They joined together by mutual agreement — this is a merger, not a takeover.</li><li><strong>C — Honda builds a factory:</strong> Building new production capacity is internal/organic growth — Honda is not buying another business.</li><li><strong>D — Netflix increases market share:</strong> Growing market share through better products or marketing is organic growth, not a takeover of another business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:mcq:135ec4d1', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Two vets agree to combine their practices and operate as one business. This is an example of a:", "options": ["Diversification", "Horizontal takeover", "Merger", "Vertical takeover"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Merger. Both vet practices mutually agreed to combine — this is the definition of a merger. It is not a takeover because neither bought the other. It is horizontal (same industry) but since they agreed to join, it is a merger not a takeover."}'::jsonb),
('business:1-6-business-growth:mcq:3a9be807', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Eve is a restaurant owner. She has successfully used social media to attract a lot of new customers. This is an example of:", "options": ["Diversification", "Invention", "Organic growth", "Skimming"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Organic growth. Eve has grown her business internally by using better marketing (social media) to gain new customers. Gaining customers through marketing is a classic organic growth method. A: Diversification = merging with an unrelated business. B: Invention = creating a new product. D: Skimming = a pricing strategy."}'::jsonb),
('business:1-6-business-growth:mcq:5effbbc0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A manufacturer of jam buys a fruit farm. This is an example of:", "options": ["A business partnership", "A vertical takeover", "Diversification", "Flexible working"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — A vertical takeover. The jam manufacturer is buying its supplier (the fruit farm), moving backwards up the supply chain — backward vertical external growth. A: A partnership is a type of business ownership, not a growth strategy. C: Diversification would mean entering an unrelated industry — fruit and jam are directly connected. D: Flexible working is an HR concept."}'::jsonb),
('business:1-6-business-growth:mcq:43c0f9f3', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A business has gained more customers by improving the way it markets its products. Which statement must be true?", "options": ["The business has developed a new product", "The business has grown organically", "The business has increased its market share", "The business has made a profit"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B — The business has grown organically. Improving marketing to gain customers is an internal method of growth — this is always organic growth. A: Not necessarily — marketing may be for existing products. C: Not necessarily — the total market may have grown faster, so market share could have fallen. D: Not necessarily — the business may still have higher costs."}'::jsonb),
